module top_module(
    inv_Y   ,
    A1  ,
    A2  ,
    B1_N
);output inv_Y   ;
    input  A1  ;
    input  A2  ;
    input  B1_N;

    // Voltage supply signals
    supply1 VPWR;
    supply0 VGND;
    supply1 VPB ;
    supply0 VNB ;

    assign inv_Y = (A1) ? 1'b1 :
               (A2) ? 1'b0 :
               (B1_N) ? 1'b1 :
               1'b0;

endmodule
